@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

<nav aria-label="Application steps" class="step-indicator mb-4">
    <ol class="list-unstyled d-flex justify-content-between align-items-center m-0 p-0">
        @for (int i = 0; i < StepNames.Count; i++)
        {
            var index = i;
            var stepNumber = i + 1;
            var isCompleted = index < CurrentStep;
            var isCurrent = index == CurrentStep;
            var isFuture = index > CurrentStep;

            <li class="step-item flex-fill text-center position-relative @(isCurrent ? "active" : "") @(isCompleted ? "completed" : "") @(isFuture ? "dimmed" : "")">
                @if (isCompleted)
                {
                    <button type="button" class="btn btn-link step-button p-0 text-decoration-none" @onclick="() => OnStepClicked.InvokeAsync(index)">
                        <span class="step-circle bg-success text-white">&#10003;</span>
                        <span class="step-label d-block mt-1 text-success fw-semibold">@StepNames[index]</span>
                    </button>
                }
                else if (isCurrent)
                {
                    <span class="step-circle bg-primary text-white">@stepNumber</span>
                    <span class="step-label d-block mt-1 text-primary fw-bold">@StepNames[index]</span>
                }
                else
                {
                    <span class="step-circle bg-secondary text-white opacity-50">@stepNumber</span>
                    <span class="step-label d-block mt-1 text-muted">@StepNames[index]</span>
                }
            </li>
        }
    </ol>
</nav>

@code {
    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter, EditorRequired] public EventCallback<int> OnStepClicked { get; set; }

    private static readonly List<string> StepNames = new()
    {
        "Personal Info",
        "Work History",
        "References",
        "Cover Letter",
        "Review & Submit"
    };
}

@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control @ValidationClass(nameof(FullName))"
           value="@FullName" @onchange="e => { FullName = e.Value?.ToString() ?? ""; FullNameChanged.InvokeAsync(FullName); ClearError(nameof(FullName)); }" />
    @if (_errors.ContainsKey(nameof(FullName)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(FullName)]</div>
    }
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @ValidationClass(nameof(Email))"
           value="@Email" @onchange="e => { Email = e.Value?.ToString() ?? ""; EmailChanged.InvokeAsync(Email); ClearError(nameof(Email)); }" />
    @if (_errors.ContainsKey(nameof(Email)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Email)]</div>
    }
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @ValidationClass(nameof(Phone))"
           value="@Phone" @onchange="e => { Phone = e.Value?.ToString() ?? ""; PhoneChanged.InvokeAsync(Phone); ClearError(nameof(Phone)); }" />
    @if (_errors.ContainsKey(nameof(Phone)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Phone)]</div>
    }
</div>

<div class="mb-3">
    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control @ValidationClass(nameof(Address))" rows="2"
              @onchange="e => { Address = e.Value?.ToString() ?? ""; AddressChanged.InvokeAsync(Address); ClearError(nameof(Address)); }">@Address</textarea>
    @if (_errors.ContainsKey(nameof(Address)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Address)]</div>
    }
</div>

@if (!string.IsNullOrEmpty(_generalError))
{
    <div class="alert alert-danger">@_generalError</div>
}

<div class="d-flex justify-content-end">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@_isValidating">
        @if (_isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating...</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private Dictionary<string, string> _errors = new();
    private string? _generalError;
    private bool _isValidating;

    private async Task HandleNext()
    {
        _errors.Clear();
        _generalError = null;

        if (string.IsNullOrWhiteSpace(FullName))
            _errors[nameof(FullName)] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            _errors[nameof(Email)] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            _errors[nameof(Phone)] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            _errors[nameof(Address)] = "Address is required.";

        if (_errors.Count > 0)
            return;

        _isValidating = true;
        try
        {
            var isValidEmail = await ValidateEmail(Email);
            if (!isValidEmail)
            {
                _errors[nameof(Email)] = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        catch
        {
            _generalError = "An error occurred while validating. Please try again.";
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void ClearError(string field)
    {
        _errors.Remove(field);
        _generalError = null;
    }

    private string ValidationClass(string field) =>
        _errors.ContainsKey(field) ? "is-invalid" : "";
}

@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass(index, "Company")" value="@entry.Company"
                           @onchange="e => UpdateEntry(index, entry with { Company = e.Value?.ToString() ?? "" })" />
                    @if (HasError(index, "Company"))
                    {
                        <div class="invalid-feedback d-block">Company name is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass(index, "Title")" value="@entry.Title"
                           @onchange="e => UpdateEntry(index, entry with { Title = e.Value?.ToString() ?? "" })" />
                    @if (HasError(index, "Title"))
                    {
                        <div class="invalid-feedback d-block">Job title is required.</div>
                    }
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control @ErrorClass(index, "StartDate")" value="@entry.StartDate.ToString("yyyy-MM-dd")"
                           @onchange="e => UpdateEntry(index, entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
                    @if (HasError(index, "StartDate"))
                    {
                        <div class="invalid-feedback d-block">Start date is required.</div>
                    }
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                           disabled="@entry.IsCurrent"
                           @onchange="e => UpdateEntry(index, entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!) })" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <div class="form-check mb-2">
                        <input type="checkbox" class="form-check-input" id="current-@index" checked="@entry.IsCurrent"
                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2"
                          @onchange="e => UpdateEntry(index, entry with { Description = e.Value?.ToString() ?? "" })">@entry.Description</textarea>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    <span class="me-1">+</span> Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private HashSet<string> _errors = new();

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        EntriesChanged.InvokeAsync(Entries);
        _errors.Remove($"{index}_Company");
        _errors.Remove($"{index}_Title");
        _errors.Remove($"{index}_StartDate");
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        _errors.Clear();
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        _errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            if (string.IsNullOrWhiteSpace(Entries[i].Company))
                _errors.Add($"{i}_Company");
            if (string.IsNullOrWhiteSpace(Entries[i].Title))
                _errors.Add($"{i}_Title");
            if (Entries[i].StartDate == default)
                _errors.Add($"{i}_StartDate");
        }

        if (_errors.Count == 0)
            await OnNext.InvokeAsync();
    }

    private bool HasError(int index, string field) => _errors.Contains($"{index}_{field}");
    private string ErrorClass(int index, string field) => HasError(index, field) ? "is-invalid" : "";

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}

@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

