                    </button>
                }
                else if (isCurrent)
                {
                    <span class="step-circle bg-primary text-white">@stepNumber</span>
                    <span class="step-label d-block mt-1 text-primary fw-bold">@StepNames[index]</span>
                }
                else
                {
                    <span class="step-circle bg-secondary text-white opacity-50">@stepNumber</span>
                    <span class="step-label d-block mt-1 text-muted">@StepNames[index]</span>
                }
            </li>
        }
