@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
    <input id="fullName" type="text" class="form-control @ValidationClass(nameof(FullName))"
           value="@FullName" @onchange="e => { FullName = e.Value?.ToString() ?? ""; FullNameChanged.InvokeAsync(FullName); ClearError(nameof(FullName)); }" />
    @if (_errors.ContainsKey(nameof(FullName)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(FullName)]</div>
    }
</div>

<div class="mb-3">
    <label for="email" class="form-label">Email <span class="text-danger">*</span></label>
    <input id="email" type="email" class="form-control @ValidationClass(nameof(Email))"
           value="@Email" @onchange="e => { Email = e.Value?.ToString() ?? ""; EmailChanged.InvokeAsync(Email); ClearError(nameof(Email)); }" />
    @if (_errors.ContainsKey(nameof(Email)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Email)]</div>
    }
</div>

<div class="mb-3">
    <label for="phone" class="form-label">Phone <span class="text-danger">*</span></label>
    <input id="phone" type="tel" class="form-control @ValidationClass(nameof(Phone))"
           value="@Phone" @onchange="e => { Phone = e.Value?.ToString() ?? ""; PhoneChanged.InvokeAsync(Phone); ClearError(nameof(Phone)); }" />
    @if (_errors.ContainsKey(nameof(Phone)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Phone)]</div>
    }
</div>

<div class="mb-3">
    <label for="address" class="form-label">Address <span class="text-danger">*</span></label>
    <textarea id="address" class="form-control @ValidationClass(nameof(Address))" rows="2"
              @onchange="e => { Address = e.Value?.ToString() ?? ""; AddressChanged.InvokeAsync(Address); ClearError(nameof(Address)); }">@Address</textarea>
    @if (_errors.ContainsKey(nameof(Address)))
    {
        <div class="invalid-feedback d-block">@_errors[nameof(Address)]</div>
    }
</div>

@if (!string.IsNullOrEmpty(_generalError))
{
    <div class="alert alert-danger">@_generalError</div>
}

<div class="d-flex justify-content-end">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@_isValidating">
        @if (_isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1" role="status"></span>
            <span>Validating...</span>
        }
        else
        {
            <span>Next</span>
        }
    </button>
</div>

@code {
    [Parameter] public string FullName { get; set; } = "";
    [Parameter] public EventCallback<string> FullNameChanged { get; set; }
    [Parameter] public string Email { get; set; } = "";
    [Parameter] public EventCallback<string> EmailChanged { get; set; }
    [Parameter] public string Phone { get; set; } = "";
    [Parameter] public EventCallback<string> PhoneChanged { get; set; }
    [Parameter] public string Address { get; set; } = "";
    [Parameter] public EventCallback<string> AddressChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;

    private Dictionary<string, string> _errors = new();
    private string? _generalError;
    private bool _isValidating;

    private async Task HandleNext()
    {
        _errors.Clear();
        _generalError = null;

        if (string.IsNullOrWhiteSpace(FullName))
            _errors[nameof(FullName)] = "Full name is required.";
        if (string.IsNullOrWhiteSpace(Email))
            _errors[nameof(Email)] = "Email is required.";
        if (string.IsNullOrWhiteSpace(Phone))
            _errors[nameof(Phone)] = "Phone is required.";
        if (string.IsNullOrWhiteSpace(Address))
            _errors[nameof(Address)] = "Address is required.";

        if (_errors.Count > 0)
            return;

        _isValidating = true;
        try
        {
            var isValidEmail = await ValidateEmail(Email);
            if (!isValidEmail)
            {
                _errors[nameof(Email)] = "Please enter a valid email address.";
                return;
            }

            await OnNext.InvokeAsync();
        }
        catch
        {
            _generalError = "An error occurred while validating. Please try again.";
        }
        finally
        {
            _isValidating = false;
        }
    }

    private void ClearError(string field)
    {
        _errors.Remove(field);
        _generalError = null;
    }

    private string ValidationClass(string field) =>
        _errors.ContainsKey(field) ? "is-invalid" : "";
}

