@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    var entry = Entries[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Position @(index + 1)</h6>
                @if (Entries.Count > 1)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveEntry(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Company Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass(index, "Company")" value="@entry.Company"
                           @onchange="e => UpdateEntry(index, entry with { Company = e.Value?.ToString() ?? "" })" />
                    @if (HasError(index, "Company"))
                    {
                        <div class="invalid-feedback d-block">Company name is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Job Title <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass(index, "Title")" value="@entry.Title"
                           @onchange="e => UpdateEntry(index, entry with { Title = e.Value?.ToString() ?? "" })" />
                    @if (HasError(index, "Title"))
                    {
                        <div class="invalid-feedback d-block">Job title is required.</div>
                    }
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-4">
                    <label class="form-label">Start Date <span class="text-danger">*</span></label>
                    <input type="date" class="form-control @ErrorClass(index, "StartDate")" value="@entry.StartDate.ToString("yyyy-MM-dd")"
                           @onchange="e => UpdateEntry(index, entry with { StartDate = DateTime.Parse(e.Value?.ToString() ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
                    @if (HasError(index, "StartDate"))
                    {
                        <div class="invalid-feedback d-block">Start date is required.</div>
                    }
                </div>
                <div class="col-md-4">
                    <label class="form-label">End Date</label>
                    <input type="date" class="form-control" value="@(entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                           disabled="@entry.IsCurrent"
                           @onchange="e => UpdateEntry(index, entry with { EndDate = string.IsNullOrEmpty(e.Value?.ToString()) ? null : DateTime.Parse(e.Value.ToString()!) })" />
                </div>
                <div class="col-md-4 d-flex align-items-end">
                    <div class="form-check mb-2">
                        <input type="checkbox" class="form-check-input" id="current-@index" checked="@entry.IsCurrent"
                               @onchange="e => UpdateEntry(index, entry with { IsCurrent = (bool)(e.Value ?? false), EndDate = (bool)(e.Value ?? false) ? null : entry.EndDate })" />
                        <label class="form-check-label" for="current-@index">Currently working here</label>
                    </div>
                </div>
            </div>

            <div class="mb-2">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="2"
                          @onchange="e => UpdateEntry(index, entry with { Description = e.Value?.ToString() ?? "" })">@entry.Description</textarea>
            </div>
        </div>
    </div>
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    <span class="me-1">+</span> Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntryModel> Entries { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<WorkEntryModel>> EntriesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private HashSet<string> _errors = new();

    private void UpdateEntry(int index, WorkEntryModel updated)
    {
        Entries[index] = updated;
        EntriesChanged.InvokeAsync(Entries);
        _errors.Remove($"{index}_Company");
        _errors.Remove($"{index}_Title");
        _errors.Remove($"{index}_StartDate");
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntryModel());
        EntriesChanged.InvokeAsync(Entries);
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
        _errors.Clear();
        EntriesChanged.InvokeAsync(Entries);
    }

    private async Task HandleNext()
    {
        _errors.Clear();

        for (int i = 0; i < Entries.Count; i++)
        {
            if (string.IsNullOrWhiteSpace(Entries[i].Company))
                _errors.Add($"{i}_Company");
            if (string.IsNullOrWhiteSpace(Entries[i].Title))
                _errors.Add($"{i}_Title");
            if (Entries[i].StartDate == default)
                _errors.Add($"{i}_StartDate");
        }

        if (_errors.Count == 0)
            await OnNext.InvokeAsync();
    }

    private bool HasError(int index, string field) => _errors.Contains($"{index}_{field}");
    private string ErrorClass(int index, string field) => HasError(index, field) ? "is-invalid" : "";

    public class WorkEntryModel
    {
        public string Company { get; set; } = "";
        public string Title { get; set; } = "";
        public DateTime StartDate { get; set; } = DateTime.Today;
        public DateTime? EndDate { get; set; }
        public bool IsCurrent { get; set; }
        public string Description { get; set; } = "";
    }
}

