toolArgs.file_text:
@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-3">
    <label for="coverLetter" class="form-label">Write your cover letter</label>
    <textarea id="coverLetter" class="form-control @(CoverLetter.Length > MaxLength ? "is-invalid" : "")" rows="12"
              maxlength="@MaxLength"
              value="@CoverLetter"
              @oninput="HandleInput">@CoverLetter</textarea>
    <div class="form-text text-end @(CoverLetter.Length > MaxLength ? "text-danger" : "")">
        @CoverLetter.Length / @MaxLength characters
    </div>
</div>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> CoverLetterChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private const int MaxLength = 2000;

    private async Task HandleInput(ChangeEventArgs e)
    {
        CoverLetter = e.Value?.ToString() ?? "";
        await CoverLetterChanged.InvokeAsync(CoverLetter);
    }

    private async Task HandleNext()
    {
        if (CoverLetter.Length <= MaxLength)
            await OnNext.InvokeAsync();
    }
}

@using static sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication.WorkHistoryStep
@using static sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication.ReferencesStep
@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

<h4 class="mb-3">Review Your Application</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center">
        <h5 class="alert-heading">Application Submitted!</h5>
        <p class="mb-0">Your application has been submitted successfully.</p>
        <p class="mb-0">Application ID: <strong>@ApplicationId</strong></p>
    </div>
}
else
{
    @* Personal Info *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(0)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Address</div>
            </div>
        </div>
    </div>

    @* Work History *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom last-child-no-border">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") &mdash;
                        @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "N/A")
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    @* References *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @foreach (var reference in References)
            {
                <div class="mb-2">
                    <strong>@reference.Name</strong> (@reference.Relationship)<br />
                    <span class="text-muted">@reference.Email &bull; @reference.Phone</span>
                </div>
            }
        </div>
    </div>

    @* Cover Letter *@
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button type="button" class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (!string.IsNullOrEmpty(_submitError))
    {
        <div class="alert alert-danger">@_submitError</div>
    }

    <div class="d-flex justify-content-between">
