arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication
@using sv_6f9711a8749d493d840adea6d4cf2403.Models
@using sv_6f9711a8749d493d840adea6d4cf2403.Services
@using static sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication.WorkHistoryStep
@using static sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication.ReferencesStep
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="text-center mb-4">Job Application</h2>

    <StepIndicator CurrentStep="_currentStep" OnStepClicked="GoToStep" />

    <div class="mt-4">
        @switch (_currentStep)
        {
            case 0:
                <PersonalInfoStep
                    @bind-FullName="_fullName"
                    @bind-Email="_email"
                    @bind-Phone="_phone"
                    @bind-Address="_address"
                    ValidateEmail="ApplicationService.ValidateEmailAsync"
                    OnNext="NextStep" />
                break;

            case 1:
                <WorkHistoryStep
                    @bind-Entries="_workEntries"
                    OnNext="NextStep"
                    OnBack="PreviousStep" />
                break;

            case 2:
                <ReferencesStep
                    @bind-References="_references"
                    OnNext="NextStep"
                    OnBack="PreviousStep" />
                break;

            case 3:
                <CoverLetterStep
                    @bind-CoverLetter="_coverLetter"
                    OnNext="NextStep"
                    OnBack="PreviousStep" />
                break;

            case 4:
                <ReviewStep
                    FullName="@_fullName"
                    Email="@_email"
                    Phone="@_phone"
                    Address="@_address"
                    WorkEntries="_workEntries"
                    References="_references"
                    CoverLetter="@_coverLetter"
                    OnBack="PreviousStep"
                    OnEditStep="GoToStep"
                    OnSubmit="SubmitApplication" />
                break;
        }
    </div>
</div>

@code {
    private int _currentStep;
    private string _fullName = "";
    private string _email = "";
    private string _phone = "";
    private string _address = "";
    private List<WorkEntryModel> _workEntries = new() { new WorkEntryModel() };
    private List<ReferenceModel> _references = new() { new ReferenceModel(), new ReferenceModel() };
    private string _coverLetter = "";

    private void NextStep() => _currentStep++;
    private void PreviousStep() => _currentStep--;
    private void GoToStep(int step)
    {
        if (step < _currentStep)
            _currentStep = step;
    }

    private async Task<int> SubmitApplication()
    {
        var personal = new PersonalInfo(_fullName, _email, _phone, _address);

        var workHistory = new WorkHistory(_workEntries.Select(e =>
            new WorkEntry(e.Company, e.Title, e.StartDate, e.IsCurrent ? null : e.EndDate, e.Description)
        ).ToList());

        var references = _references.Select(r =>
            new Reference(r.Name, r.Relationship, r.Email, r.Phone)
        ).ToList();

        var application = new JobApplication(personal, workHistory, references, _coverLetter);

        return await ApplicationService.SubmitApplicationAsync(application);
    }
}

.step-indicator ol {
    counter-reset: step;
}

.step-item {
    position: relative;
}

.step-item:not(:last-child)::after {
    content: "";
    position: absolute;
    top: 18px;
    left: 55%;
    width: 90%;
    height: 2px;
    background-color: #dee2e6;
    z-index: 0;
}

.step-item.completed:not(:last-child)::after {
    background-color: #198754;
}

.step-circle {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    width: 36px;
    height: 36px;
    border-radius: 50%;
    font-weight: bold;
    font-size: 0.9rem;
    position: relative;
    z-index: 1;
}

.step-label {
    font-size: 0.8rem;
}

.step-button {
    border: none;
    background: none;
    cursor: pointer;
}

.step-button:hover .step-label {
    text-decoration: underline;
}

.step-item.dimmed {
    opacity: 0.5;
}

