73.     [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
74.     [Parameter, EditorRequired] public Func<string, Task<bool>> ValidateEmail { get; set; } = default!;
75. 
76.     private Dictionary<string, string> _errors = new();
77.     private string? _generalError;
78.     private bool _isValidating;
79. 
80.     private async Task HandleNext()
81.     {
82.         _errors.Clear();
83.         _generalError = null;
84. 
85.         if (string.IsNullOrWhiteSpace(FullName))
86.             _errors[nameof(FullName)] = "Full name is required.";
87.         if (string.IsNullOrWhiteSpace(Email))
88.             _errors[nameof(Email)] = "Email is required.";
89.         if (string.IsNullOrWhiteSpace(Phone))
