91.         if (string.IsNullOrWhiteSpace(Address))
92.             _errors[nameof(Address)] = "Address is required.";
93. 
94.         if (_errors.Count > 0)
95.             return;
96. 
97.         _isValidating = true;
98.         try
99.         {
100.             var isValidEmail = await ValidateEmail(Email);
101.             if (!isValidEmail)
102.             {
