    private void OnFieldChanged(int index, string field, ChangeEventArgs e)
    {
        var val = e.Value?.ToString() ?? string.Empty;
        var entry = Entries[index];

        switch (field)
        {
            case nameof(WorkEntryModel.Company): entry.Company = val; break;
            case nameof(WorkEntryModel.Title): entry.Title = val; break;
