toolArgs.old_str:
@namespace sv_6f9711a8749d493d840adea6d4cf2403.Components.JobApplication

<h4 class="mb-3">References</h4>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    var reference = References[index];

    <div class="card mb-3">
        <div class="card-body">
            <div class="d-flex justify-content-between align-items-center mb-2">
                <h6 class="card-title mb-0">Reference @(index + 1)</h6>
                @if (References.Count > 2)
                {
                    <button type="button" class="btn btn-outline-danger btn-sm" @onclick="() => RemoveReference(index)">Remove</button>
                }
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Name <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass(index, "Name")" value="@reference.Name"
                           @onchange="e => UpdateReference(index, reference with { Name = e.Value?.ToString() ?? "" })" />
                    @if (HasError(index, "Name"))
                    {
                        <div class="invalid-feedback d-block">Name is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Relationship <span class="text-danger">*</span></label>
                    <input type="text" class="form-control @ErrorClass(index, "Relationship")" value="@reference.Relationship"
                           @onchange="e => UpdateReference(index, reference with { Relationship = e.Value?.ToString() ?? "" })" />
                    @if (HasError(index, "Relationship"))
                    {
                        <div class="invalid-feedback d-block">Relationship is required.</div>
                    }
                </div>
            </div>

            <div class="row mb-2">
                <div class="col-md-6">
                    <label class="form-label">Email <span class="text-danger">*</span></label>
                    <input type="email" class="form-control @ErrorClass(index, "Email")" value="@reference.Email"
                           @onchange="e => UpdateReference(index, reference with { Email = e.Value?.ToString() ?? "" })" />
                    @if (HasError(index, "Email"))
                    {
                        <div class="invalid-feedback d-block">Email is required.</div>
                    }
                </div>
                <div class="col-md-6">
                    <label class="form-label">Phone <span class="text-danger">*</span></label>
                    <input type="tel" class="form-control @ErrorClass(index, "Phone")" value="@reference.Phone"
                           @onchange="e => UpdateReference(index, reference with { Phone = e.Value?.ToString() ?? "" })" />
                    @if (HasError(index, "Phone"))
                    {
                        <div class="invalid-feedback d-block">Phone is required.</div>
                    }
                </div>
            </div>
        </div>
    </div>
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary mb-3" @onclick="AddReference">
        <span class="me-1">+</span> Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<ReferenceModel> References { get; set; } = new();
    [Parameter, EditorRequired] public EventCallback<List<ReferenceModel>> ReferencesChanged { get; set; }
    [Parameter, EditorRequired] public EventCallback OnNext { get; set; }
    [Parameter, EditorRequired] public EventCallback OnBack { get; set; }

    private HashSet<string> _errors = new();

    private void UpdateReference(int index, ReferenceModel updated)
    {
        References[index] = updated;
        ReferencesChanged.InvokeAsync(References);
        _errors.RemoveWhere(e => e.StartsWith($"{index}_"));
    }

    private void AddReference()
    {
        if (References.Count < 3)
        {
            References.Add(new ReferenceModel());
            ReferencesChanged.InvokeAsync(References);
        }
    }

    private void RemoveReference(int index)
    {
        References.RemoveAt(index);
        _errors.Clear();
        ReferencesChanged.InvokeAsync(References);
    }

    private async Task HandleNext()
    {
        _errors.Clear();

        for (int i = 0; i < References.Count; i++)
        {
            if (string.IsNullOrWhiteSpace(References[i].Name))
                _errors.Add($"{i}_Name");
            if (string.IsNullOrWhiteSpace(References[i].Relationship))
                _errors.Add($"{i}_Relationship");
            if (string.IsNullOrWhiteSpace(References[i].Email))
                _errors.Add($"{i}_Email");
            if (string.IsNullOrWhiteSpace(References[i].Phone))
                _errors.Add($"{i}_Phone");
        }

        if (_errors.Count == 0)
            await OnNext.InvokeAsync();
    }

    private bool HasError(int index, string field) => _errors.Contains($"{index}_{field}");
    private string ErrorClass(int index, string field) => HasError(index, field) ? "is-invalid" : "";

    public record ReferenceModel
    {
        public string Name { get; set; } = "";
        public string Relationship { get; set; } = "";
        public string Email { get; set; } = "";
        public string Phone { get; set; } = "";
    }
}

